// WHY $input.all() instead of $input.first():
// GitHub Contents API returns one n8n item per file, not a single item
// containing an array. So we collect all items and map them directly.
const items = $input.all();
const today = new Date().toISOString().split('T')[0];

if (items.length === 0) {
  return [];
}

const mdFiles = items
  .map(i => i.json)
  .filter(f => f.type === 'file' && f.name && f.name.endsWith('.md'));

if (mdFiles.length === 0) {
  return [];
}

return mdFiles.map(f => ({ json: {
  file_url: f.url,
  file_name: f.name,
  checked_date: today
} }));

const items = $input.all();
const today = new Date().toISOString().split('T')[0];
const followupsNeeded = [];

for (const item of items) {
  try {
    const content = Buffer.from(item.json.content || '', 'base64').toString('utf-8');

    const companyMatch = content.match(/^company:\s*"?([^"\n]+)"?/m);
    const roleMatch    = content.match(/^role:\s*"?([^"\n]+)"?/m);
    const company = companyMatch ? companyMatch[1].trim() : 'Unknown';
    const role    = roleMatch    ? roleMatch[1].trim()    : 'Position';

    // WHY split on | and trim: dates are in a markdown table:
    // | Day 3 | 2026-03-23 | ⏳ Pending |
    // Split the line by | gives ['', ' Day 3 ', ' 2026-03-23 ', ' ⏳ Pending ', '']
    function extractDate(text, label) {
      const line = text.split('\n').find(l => l.includes(label));
      if (!line) return null;
      const parts = line.split('|').map(p => p.trim());
      const datePart = parts.find(p => /^\d{4}-\d{2}-\d{2}$/.test(p));
      return datePart || null;
    }

    const checks = [
      { date: extractDate(content, 'Day 3'),  type: 'day_3',  label: 'Day 3 Check-In' },
      { date: extractDate(content, 'Day 7'),  type: 'day_7',  label: 'Day 7 Follow-Up' },
      { date: extractDate(content, 'Day 30'), type: 'day_30', label: 'Day 30 Check-In' },
      { date: extractDate(content, 'Day 90'), type: 'day_90', label: '90-Day Check-In' }
    ];

    // Filter by today's date — only process follow-ups due today
    for (const check of checks) {
      if (check.date === today) {
        followupsNeeded.push({ company, role, followup_type: check.type, followup_label: check.label, due_date: check.date });
      }
    }
  } catch(e) { /* skip */ }
}


// WHY read from Fetch CV from GitHub's input chain: the Set Type node ran before
// Fetch CV from GitHub, so its output is available via $('Set Type day_3') etc.
// But since we don't know which trigger fired, we read it from the first item
// that came through — it was injected by whichever Set Type node ran.
// Actually the cleanest way: pass it through Fetch CV node by reading $input context.
// Since Set Type connects to Fetch CV which connects here, we can't directly read it.
// Instead, we use a simpler approach: read the current hour to determine type.
// 9:00-9:29 = day_3, 9:30-9:59 = day_7, 10:00-10:29 = day_30, 10:30+ = day_90
const now = new Date();
const hour = now.getHours();
const minute = now.getMinutes();
let typeFilter = null;
if (hour === 9 && minute < 30) typeFilter = 'day_3';
else if (hour === 9 && minute >= 30) typeFilter = 'day_7';
else if (hour === 10 && minute < 30) typeFilter = 'day_30';
else if (hour === 10 && minute >= 30) typeFilter = 'day_90';
if (typeFilter) {
  followupsNeeded = followupsNeeded.filter(f => f.followup_type === typeFilter);
}
return [{ json: { followups_needed: followupsNeeded, checked_date: today, files_checked: items.length } }];

const data = $input.first().json;
const followups = data.followups_needed || [];

// WHY read CV by node name: the CV was fetched at the start of the workflow
// so the AI can pick the most relevant projects for this specific role,
// rather than us hardcoding a fixed list.
const cvText = $('Fetch CV from GitHub').first().json || '';
const cvString = typeof cvText === 'string' ? cvText.substring(0, 1500) : JSON.stringify(cvText).substring(0, 1500);

return followups.map(f => {
  let prompt = '';

  if (f.followup_type === 'day_3') {
    prompt =
      'Write a follow-up email to a recruiter at ' + f.company + ' for the ' + f.role + ' position. ' +
      'It has been 3 days since I applied. Tone: confident, concise, not desperate. Maximum 4 sentences. ' +
      'Rules: ' +
      '1. Open with ONE specific, recent (2025-2026) thing ' + f.company + ' has done -- a product launch, technical achievement, or engineering decision. Be specific, not vague. ' +
      '2. From my CV below, pick the ONE project most relevant to ' + f.role + ' at ' + f.company + ' and reference it with a specific metric or technical detail. ' +
      '3. Ask about next steps. ' +
      '4. Banned phrases: excited to apply, passionate about, would love the opportunity, looking forward to hearing from you. ' +
      '5. Sound like a peer, not a job seeker. ' +
      '6. After the main email, write 2 alternative versions with different opening hooks but same structure. ' +
      '7. Add a short note: what makes each version likely to get a response. ' +
      'Sign off: Odeliya Charitonova\n\nMy CV:\n' + cvString;
  } else if (f.followup_type === 'day_7') {
    prompt =
      'Write a 7-day follow-up email to a recruiter at ' + f.company + ' for the ' + f.role + ' position. ' +
      'No response yet. Tone: self-assured, brief. Maximum 4 sentences. ' +
      'Rules: ' +
      '1. From my CV below, pick the ONE project most relevant to ' + f.role + ' and mention one specific technical detail or metric that proves I can do this job. ' +
      '2. Reference something technically specific about ' + f.company + ' -- a system they run at scale, a technical blog post, or a recent engineering decision. ' +
      '3. Ask directly: is the role still active, and would it make sense to connect? ' +
      '4. Banned phrases: excited, passionate, would love, looking forward. Sound like someone with options, not someone waiting by the phone. ' +
      '5. After the main email, write 2 alternative versions with different hooks. ' +
      '6. Add a note on what makes each version likely to get a response. ' +
      'Sign off: Odeliya Charitonova\n\nMy CV:\n' + cvString;
  } else if (f.followup_type === 'day_30') {
    prompt =
      'Write a 30-day check-in email to a recruiter at ' + f.company + ' for the ' + f.role + ' position. ' +
      'Tone: warm but direct. 3 sentences maximum. ' +
      'Rules: ' +
      '1. From my CV below, pick the most impressive project relevant to ' + f.role + ' and mention it with a specific detail. ' +
      '2. Reference one real thing about ' + f.company + '\'s engineering culture or tech that genuinely appeals. ' +
      '3. Ask if the role is still active or if there are similar openings. ' +
      '4. No filler, no desperation. ' +
      '5. Write 2 alternative versions with different hooks, plus a note on what makes each effective. ' +
      'Sign off: Odeliya Charitonova\n\nMy CV:\n' + cvString;
  } else {
    prompt =
      'Write a 90-day reconnection email to someone at ' + f.company + ' for the ' + f.role + ' position. ' +
      'Tone: confident and curious, not desperate. 3 sentences maximum. ' +
      'Rules: ' +
      '1. Do not mention the rejection or the wait. Reconnect naturally. ' +
      '2. From my CV below, lead with the most impressive project relevant to ' + f.role + ' -- pick based on relevance, not recency. ' +
      '3. Ask if there are openings that might fit, or if they would be open to a quick conversation. ' +
      '4. Sound like someone who has grown, not someone still waiting. ' +
      '5. Write 2 alternative versions plus notes on effectiveness. ' +
      'Sign off: Odeliya Charitonova\n\nMy CV:\n' + cvString;
  }

  return { json: {
    company: f.company,
    role: f.role,
    followup_type: f.followup_type,
    followup_label: f.followup_label,
    due_date: f.due_date,
    body: JSON.stringify({
      model: 'llama-3.1-8b-instant',
      messages: [{ role: 'user', content: prompt }],
      temperature: 0.85,
      max_tokens: 512
    })
  } };
});

const groqItems    = $input.all();
const prepareItems = $('Prepare Follow-Up Prompts').all();
const today = new Date().toISOString().split('T')[0];

// WHY encode draft as base64 in the URL:
// The approval webhook needs the full draft text to show the confirmation page.
// Base64 encoding makes it URL-safe without losing content.
const n8nBaseUrl = 'http://localhost:5678';

let html = '<html><body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;padding:20px;">';
html += '<h2 style="color:#007bff;">Daily Follow-Up Digest - ' + today + '</h2>';
html += '<p>You have <strong>' + groqItems.length + '</strong> follow-up(s) due today.</p>';
html += '<p style="color:#dc3545;font-weight:bold;">Review each draft carefully before approving. Clicking Approve opens a confirmation page first.</p>';

for (let i = 0; i < groqItems.length; i++) {
  const meta  = prepareItems[i]?.json || {};
  const draft = groqItems[i]?.json?.choices?.[0]?.message?.content || '[No draft]';

  // Encode draft + metadata for the approval webhook
  const payload = Buffer.from(JSON.stringify({
    draft,
    company: meta.company || '',
    role: meta.role || '',
    followup_label: meta.followup_label || '',
    due_date: meta.due_date || today
  })).toString('base64');

  const approveUrl = n8nBaseUrl + '/webhook/approve-followup?payload=' + encodeURIComponent(payload);

  html +=
    '<div style="border:1px solid #dee2e6;border-radius:5px;padding:15px;margin-bottom:20px;">' +
    '<h3 style="margin-top:0;">' + (meta.company||'') + ' - ' + (meta.role||'') + '</h3>' +
    '<p><strong>Type:</strong> ' + (meta.followup_label||'') + ' | <strong>Due:</strong> ' + (meta.due_date||'') + '</p>' +
    '<h4>Draft:</h4>' +
    '<pre style="background:#f8f9fa;padding:15px;border-radius:5px;white-space:pre-wrap;border-left:4px solid #007bff;">' + draft + '</pre>' +
    '<a href="' + approveUrl + '" style="display:inline-block;background:#28a745;color:white;padding:10px 20px;border-radius:5px;text-decoration:none;font-weight:bold;margin-top:10px;">Review &amp; Approve</a>' +
    '<p style="color:#6c757d;font-size:0.85em;margin-top:8px;">Clicking opens a confirmation page. Nothing sends until you confirm.</p>' +
    '</div>';
}

html += '</body></html>';
return [{ json: { email_html: html, followup_count: groqItems.length, date: today } }];
